// Resimler için native lazy
<img src='photo.jpg' loading='lazy' />

// JS dinamik import
const module = await import('./heavy-module.js');

// Intersection Observer
const observer = new IntersectionObserver(entries => {
  entries.forEach(e => {
    if (e.isIntersecting) loadContent(e.target);
  });
});
observer.observe(placeholder);
```

**Frontend Karbon Optimizasyonu: Kullanıcı Cihazının Enerji Tüketimi**

Bir web sayfası her yüklenişinde kullanıcı cihazında enerji harcar. Milyonlarca kullanıcıda bu birikerek önemli bir karbon ayak izi oluşturur.

**Web Karbon Hesabı:**
```javascript
// websitecarbon.com API ile otomatik ölçüm
const { default: fetch } = require('node-fetch');

async function getWebsiteCarbon(url) {
  const response = await fetch(
    `https://api.websitecarbon.com/site?url=${encodeURIComponent(url)}`
  );
  const data = await response.json();
  console.log(`CO₂/sayfa görüntüleme: ${data.statistics.co2.renewable.grams}g`);
  console.log(`Yıllık (10K ziyaret): ${data.statistics.co2.renewable.grams * 10000 / 1000} kg`);
}
```

